const MOET_TOPS = [0.5,1,2,5,10,20,30,50];

function buildMoetAnchors(tableKey, combo){
  return MOET_TOPS.map(top=>{
    const hsa = hsaFromTop(top, tableKey);
    const hsaAll = hsaFromTop(top, 'ALL');
    const thpt = interpMap(VNU_HSA_EQ_2025[combo] || VNU_HSA_EQ_2025.A00, hsaAll);
    return {top, hsa, hsaAll, thpt, combo, tableKey};
  }).filter(r=>Number.isFinite(r.hsa) && Number.isFinite(r.thpt));
}
function findMoetIntervalByThpt(thpt, anchors){
  const arr = anchors.slice().sort((a,b)=>a.top-b.top);
  for(let i=0;i<arr.length-1;i++){
    const high = arr[i], low = arr[i+1];
    const max = Math.max(high.thpt, low.thpt), min = Math.min(high.thpt, low.thpt);
    if(thpt <= max && thpt >= min) return {high, low};
  }
  return null;
}
function findMoetIntervalByHsa(hsa, anchors){
  const arr = anchors.slice().sort((a,b)=>a.top-b.top);
  for(let i=0;i<arr.length-1;i++){
    const high = arr[i], low = arr[i+1];
    const max = Math.max(high.hsa, low.hsa), min = Math.min(high.hsa, low.hsa);
    if(hsa <= max && hsa >= min) return {high, low};
  }
  return null;
}
function convertMoetThptToHsa(thpt, anchors){
  const it = findMoetIntervalByThpt(thpt, anchors);
  if(!it) return {score:null, interval:null, note:'Ngoài các khoảng mốc hiện có'};
  const {high, low} = it;
  const score = low.hsa + (thpt - low.thpt) * (high.hsa - low.hsa) / (high.thpt - low.thpt);
  return {score, interval:it, note:`Nằm trong khoảng top ${high.top}% – ${low.top}%`};
}
function convertMoetHsaToThpt(hsa, anchors){
  const it = findMoetIntervalByHsa(hsa, anchors);
  if(!it) return {score:null, interval:null, note:'Ngoài các khoảng mốc hiện có'};
  const {high, low} = it;
  const score = low.thpt + (hsa - low.hsa) * (high.thpt - low.thpt) / (high.hsa - low.hsa);
  return {score, interval:it, note:`Nằm trong khoảng top ${high.top}% – ${low.top}%`};
}
function renderMoet(){
  if(!$('moetAnchorTable')) return;
  const state=currentInput();
  const tableKey=state.rankTable;
  const combo=state.combo;
  const anchors=buildMoetAnchors(tableKey, combo);
  const thpt=Number($('moetThptInput')?.value || 27);
  const hsa=Number($('moetHsaInput')?.value || state.score || 98);
  const toHsa=convertMoetThptToHsa(thpt, anchors);
  const toThpt=convertMoetHsaToThpt(hsa, anchors);
  $('moetResultBox').innerHTML = [
    {k:'THPT → HSA',v:fmt(toHsa.score,2),s:toHsa.note},
    {k:'HSA → THPT',v:fmt(toThpt.score,2),s:toThpt.note},
    {k:'Bảng đang dùng',v:combo,s:(HSA2026_RANK_TABLES[tableKey]?.label || tableKey)}
  ].map(x=>`<div class="box"><span>${esc(x.k)}</span><b>${esc(x.v)}</b><div class="small">${esc(x.s)}</div></div>`).join('');

  const explainInterval = (it, direction) => {
    if(!it) return 'Không tìm được khoảng nội suy phù hợp trong bảng mốc hiện tại.';
    const {high, low}=it;
    if(direction==='thpt') {
      return `Điểm ${fmt(thpt)} nằm giữa A_high=${fmt(high.thpt)} ở top ${high.top}% và A_low=${fmt(low.thpt)} ở top ${low.top}%; nội suy ra HSA=${fmt(toHsa.score)}.`;
    }
    return `Điểm HSA ${fmt(hsa)} nằm giữa X_high=${fmt(high.hsa)} ở top ${high.top}% và X_low=${fmt(low.hsa)} ở top ${low.top}%; nội suy ra ${combo}=${fmt(toThpt.score)}.`;
  };
  $('moetThptExplain').textContent = explainInterval(toHsa.interval,'thpt');
  $('moetHsaExplain').textContent = explainInterval(toThpt.interval,'hsa');

  $('moetAnchorTable').innerHTML =
    '<thead><tr><th>Mốc top</th><th>X_i HSA theo bảng đã chọn</th><th>HSA bảng chung cùng top</th><th>A_i '+esc(combo)+' tham chiếu</th><th>Cách dùng</th></tr></thead><tbody>'+
    anchors.map((r,i)=>`<tr><td><b>${r.top}%</b></td><td>${fmt(r.hsa,2)}</td><td>${fmt(r.hsaAll,2)}</td><td><b>${fmt(r.thpt,2)}</b></td><td>${i<anchors.length-1?'Nội suy với mốc '+anchors[i+1].top+'%':'Mốc dưới cùng'}</td></tr>`).join('')+
    '</tbody>';
}


